def solve(ftp_data, parcel_requests):
    reservations = []

    for flight in ftp_data:
        flight_id = flight['flight_id']
        available_capacity = flight['available_capacity']

        for request in parcel_requests:
            if request['weight'] <= available_capacity:
                reservations.append({
                    'flight_id': flight_id,
                    'parcel_id': request['parcel_id'],
                    'weight': request['weight']
                })
                available_capacity -= request['weight']

                if available_capacity <= 0:
                    break

    return reservations
